const row = $json;

const studentName  = (row['Your Name'] || '').trim();
const phoneRaw     = (row['WhatsApp Number'] || '').trim();
const subject      = (row['Subject Name'] || '').trim();
const videoUrl     = (row['Lecture Video URL'] || '').trim();
const examRevision = (row['Exam Revision?'] || 'No').trim();

if (!studentName || !phoneRaw || !videoUrl) {
  throw new Error('Name, WhatsApp Number, and Video URL are required.');
}

let phone = phoneRaw.replace(/[\s\-\(\)]/g, '');
if (!phone.startsWith('+')) phone = '+' + phone;
const whatsappTo = 'whatsapp:' + phone;

const examTag = examRevision.toLowerCase() === 'yes' ? 'EXAM IMPORTANT' : 'Regular Lecture';

return [{ json: { studentName, phone, whatsappTo, subject, videoUrl, examRevision, examTag } }];

