const output = $input.first().json.output || '';

const kpMatch = output.match(/KEY_POINTS:\s*([\s\S]*?)(?=\nEXAM_CONCEPTS:|$)/);
const ecMatch = output.match(/EXAM_CONCEPTS:\s*([\s\S]*?)(?=\nNEVER_FORGET:|$)/);
const nfMatch = output.match(/NEVER_FORGET:\s*([\s\S]*)$/);

const keyPoints    = kpMatch ? kpMatch[1].trim() : '';
const examConcepts = ecMatch ? ecMatch[1].trim() : '';
const neverForget  = nfMatch ? nfMatch[1].trim() : '';

const ctx = $('2. Code — Validate and Prepare').item.json;
const subject      = ctx.subject;
const examTag      = ctx.examTag;
const whatsappTo   = ctx.whatsappTo;
const studentName  = ctx.studentName;
const phone        = ctx.phone;
const videoUrl     = ctx.videoUrl;
const examRevision = ctx.examRevision;

const message = [
  `*Study Digest — ${subject}*`,
  `${examTag}`,
  ``,
  `━━━━━━━━━━━━`,
  `*5 KEY POINTS*`,
  `━━━━━━━━━━━━`,
  keyPoints,
  ``,
  `━━━━━━━━━━━━`,
  `*EXAM IMPORTANT*`,
  `━━━━━━━━━━━━`,
  examConcepts,
  ``,
  `*NEVER FORGET:*`,
  neverForget
].join('\n');

return [{ json: { message, keyPoints, examConcepts, neverForget, whatsappTo, studentName, phone, subject, videoUrl, examTag, examRevision } }];
